using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Plataforma que aparece/desaparece periodicamente (add-on opcional —
/// combina com MovingPlatform ou usa-se sozinha numa plataforma estática).
///
/// Enquanto "desaparecida": colisores e SpriteRenderers desligados (não pode
/// ser pisada nem vista). "tempoAviso" faz a plataforma "tremer"/ficar
/// semi-transparente um pouco antes de desaparecer, para dar tempo de reacção.
/// </summary>
[DisallowMultipleComponent]
public class PlatformBlink : MonoBehaviour
{
    [Header("Temporização")]
    [Tooltip("Tempo (segundos) visível/sólida.")]
    [Min(0.05f)] public float tempoVisivel = 2f;

    [Tooltip("Tempo (segundos) invisível/sem colisão.")]
    [Min(0.05f)] public float tempoInvisivel = 1f;

    [Tooltip("Começa visível (true) ou invisível (false)?")]
    public bool comecaVisivel = true;

    [Header("Aviso antes de desaparecer")]
    [Tooltip("Duração (segundos) do aviso semi-transparente antes de desaparecer. 0 = sem aviso (desaparece de repente).")]
    [Min(0f)] public float tempoAviso = 0.5f;

    [Range(0f, 1f)] public float alphaDoAviso = 0.35f;

    [Header("Visual")]
    [Tooltip("Vazio = usa todos os SpriteRenderer em filhos.")]
    public SpriteRenderer[] spriteRenderers;

    [Header("Eventos")]
    public UnityEvent<bool> onVisibilidadeAlterada;

    private Collider2D[] _colliders;
    private float _timer;
    private bool _visible;

    private void Awake()
    {
        _colliders = GetComponentsInChildren<Collider2D>();

        if (spriteRenderers == null || spriteRenderers.Length == 0)
            spriteRenderers = GetComponentsInChildren<SpriteRenderer>();

        _visible = comecaVisivel;
        _timer = _visible ? tempoVisivel : tempoInvisivel;

        SetActive(_visible);
        SetAlpha(1f);
    }

    private void Update()
    {
        _timer -= Time.deltaTime;

        // Aviso: fica semi-transparente nos últimos "tempoAviso" segundos antes de desaparecer.
        if (_visible && tempoAviso > 0f && _timer <= tempoAviso)
        {
            float t = Mathf.Clamp01(_timer / tempoAviso);
            SetAlpha(Mathf.Lerp(alphaDoAviso, 1f, t));
        }

        if (_timer > 0f) return;

        _visible = !_visible;
        _timer = _visible ? tempoVisivel : tempoInvisivel;

        SetActive(_visible);
        SetAlpha(1f);

        onVisibilidadeAlterada?.Invoke(_visible);
    }

    private void SetActive(bool active)
    {
        foreach (var col in _colliders)
            if (col != null) col.enabled = active;

        foreach (var sr in spriteRenderers)
            if (sr != null) sr.enabled = active;
    }

    private void SetAlpha(float alpha)
    {
        foreach (var sr in spriteRenderers)
        {
            if (sr == null) continue;
            var c = sr.color;
            c.a = alpha;
            sr.color = c;
        }
    }
}
